/**
 * Official DRC higher education establishments data
 * Source: Ministère de l'Enseignement Supérieur et Universitaire
 */

function getType(denomination) {
  const d = (denomination || '').toUpperCase();
  if (d.startsWith('UNIVERSI') || d.startsWith('FACULTE') || d.startsWith('FACULTÉ') || d.startsWith('CENTRE UNIVERSITAIRE')) return 'Université';
  if (d.startsWith('ECOLE') || d.startsWith('ÉCOLE')) return 'École Supérieure';
  return 'Institut Supérieur';
}

